import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const T = {
  bg: '#07070f', bg1: '#0d0d1c', bg2: '#12122a',
  border: '#ffffff0f', border2: '#ffffff1a',
  text: '#f0f0f5', text2: '#9090a8', text3: '#5a5a72',
  purple: '#7c6fef', purpleL: '#a99ef7', green: '#22c98e', red: '#f06060',
};

export default function AuthPage() {
  const [mode, setMode] = useState('login');
  const [form, setForm] = useState({ name: '', email: '', password: '', role: 'student' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login, register } = useAuth();
  const navigate = useNavigate();

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const submit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      if (mode === 'login') {
        await login(form.email, form.password);
      } else {
        await register(form.name, form.email, form.password, form.role);
      }
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.error || 'Something went wrong');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: T.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}>
      <div style={{ width: '100%', maxWidth: 420 }}>
        {/* Logo */}
        <div style={{ textAlign: 'center', marginBottom: 36 }}>
          <div style={{ width: 52, height: 52, borderRadius: 16, background: T.purple + '33', border: `1px solid ${T.purple}66`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, color: T.purple, fontWeight: 800, margin: '0 auto 14px' }}>L</div>
          <div style={{ color: T.text, fontSize: 24, fontWeight: 800, letterSpacing: '-0.03em' }}>LearnFlow<span style={{ color: T.purple }}>.</span></div>
          <div style={{ color: T.text3, fontSize: 13, marginTop: 4 }}>Your online learning platform</div>
        </div>

        <div style={{ background: T.bg1, border: `1px solid ${T.border2}`, borderRadius: 18, padding: 32 }}>
          {/* Tabs */}
          <div style={{ display: 'flex', background: T.bg2, borderRadius: 10, padding: 3, marginBottom: 28 }}>
            {['login', 'register'].map(m => (
              <button key={m} onClick={() => { setMode(m); setError(''); }} style={{ flex: 1, padding: '8px', borderRadius: 8, border: 'none', background: mode === m ? T.bg1 : 'transparent', color: mode === m ? T.text : T.text3, fontWeight: mode === m ? 600 : 400, cursor: 'pointer', fontSize: 14, transition: 'all 0.2s' }}>
                {m === 'login' ? 'Sign In' : 'Register'}
              </button>
            ))}
          </div>

          <form onSubmit={submit} style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            {mode === 'register' && (
              <div>
                <label style={{ color: T.text2, fontSize: 12, display: 'block', marginBottom: 6 }}>Full Name</label>
                <input value={form.name} onChange={e => set('name', e.target.value)} placeholder="Your full name" required
                  style={{ width: '100%', background: T.bg2, border: `1px solid ${T.border2}`, borderRadius: 10, padding: '11px 14px', color: T.text, fontSize: 14, outline: 'none', boxSizing: 'border-box' }} />
              </div>
            )}

            <div>
              <label style={{ color: T.text2, fontSize: 12, display: 'block', marginBottom: 6 }}>Email</label>
              <input type="email" value={form.email} onChange={e => set('email', e.target.value)} placeholder="you@example.com" required
                style={{ width: '100%', background: T.bg2, border: `1px solid ${T.border2}`, borderRadius: 10, padding: '11px 14px', color: T.text, fontSize: 14, outline: 'none', boxSizing: 'border-box' }} />
            </div>

            <div>
              <label style={{ color: T.text2, fontSize: 12, display: 'block', marginBottom: 6 }}>Password</label>
              <input type="password" value={form.password} onChange={e => set('password', e.target.value)} placeholder="Min 6 characters" required
                style={{ width: '100%', background: T.bg2, border: `1px solid ${T.border2}`, borderRadius: 10, padding: '11px 14px', color: T.text, fontSize: 14, outline: 'none', boxSizing: 'border-box' }} />
            </div>

            {mode === 'register' && (
              <div>
                <label style={{ color: T.text2, fontSize: 12, display: 'block', marginBottom: 6 }}>I am a...</label>
                <div style={{ display: 'flex', gap: 8 }}>
                  {['student', 'instructor'].map(r => (
                    <button key={r} type="button" onClick={() => set('role', r)} style={{ flex: 1, padding: '10px', borderRadius: 10, border: `1px solid ${form.role === r ? T.purple + '66' : T.border}`, background: form.role === r ? T.purple + '22' : T.bg2, color: form.role === r ? T.purpleL : T.text3, cursor: 'pointer', fontSize: 14, fontWeight: form.role === r ? 600 : 400, transition: 'all 0.15s', textTransform: 'capitalize' }}>
                      {r === 'student' ? '🎓 Student' : '👨‍🏫 Instructor'}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {error && (
              <div style={{ background: T.red + '18', border: `1px solid ${T.red}44`, borderRadius: 8, padding: '10px 14px', color: T.red, fontSize: 13 }}>
                {error}
              </div>
            )}

            <button type="submit" disabled={loading} style={{ background: loading ? T.bg2 : T.purple, border: 'none', borderRadius: 10, padding: '13px', color: loading ? T.text3 : '#fff', fontWeight: 700, fontSize: 15, cursor: loading ? 'not-allowed' : 'pointer', transition: 'all 0.2s', marginTop: 4 }}>
              {loading ? 'Please wait...' : mode === 'login' ? 'Sign In →' : 'Create Account →'}
            </button>
          </form>
        </div>

        <div style={{ textAlign: 'center', marginTop: 20, color: T.text3, fontSize: 13 }}>
          {mode === 'login' ? "Don't have an account? " : 'Already have an account? '}
          <button onClick={() => { setMode(mode === 'login' ? 'register' : 'login'); setError(''); }} style={{ background: 'none', border: 'none', color: T.purple, cursor: 'pointer', fontSize: 13 }}>
            {mode === 'login' ? 'Register' : 'Sign In'}
          </button>
        </div>
      </div>
    </div>
  );
}
